mapper.select:
/* 파일 라이브러리 건수 repository.selectDocFileLibraryListCnt */ SELECT COUNT(*) FROM TB_DOC_FILE A WHERE A.USE_YN = 'Y'
AND A.URL_ID IS NOT NULL AND A.URL_ID IS NULL
AND A.CATEGORY_ID = #{categoryId}
AND ( A.FILE_NAME LIKE CONCAT('%', #{findContent}, '%') OR A.DOC_DESC LIKE CONCAT('%', #{findContent}, '%') )

/* 파일 라이브러리 목록 repository.selectDocFileLibraryList */ SELECT A.DOC_FILE_ID , A.CATEGORY_ID , ( WITH RECURSIVE CAT_UP AS ( SELECT CATEGORY_ID, CATEGORY_NAME, PARN_CAT_ID, 1 AS DEPTH FROM TB_CONTENT_CAT WHERE CATEGORY_ID = A.CATEGORY_ID UNION ALL SELECT C.CATEGORY_ID, C.CATEGORY_NAME, C.PARN_CAT_ID, CU.DEPTH + 1 FROM TB_CONTENT_CAT C INNER JOIN CAT_UP CU ON C.CATEGORY_ID = CU.PARN_CAT_ID ) SELECT GROUP_CONCAT(CU.CATEGORY_NAME ORDER BY CU.DEPTH DESC SEPARATOR ' > ') FROM CAT_UP CU ) AS CATEGORY_NAME , A.SEC_LVL , A.DOC_DESC , A.FILE_NAME , A.FILE_PATH , A.FILE_SIZE , A.FILE_TYPE , A.KEYWORDS , A.DOC_SRC , A.USE_YN , A.CREATE_DT , A.MODIFY_DT , A.CREATE_USER_ID , A.MODIFY_USER_ID , ( SELECT COUNT(*) FROM TB_DS_DOC DD INNER JOIN TB_DS D ON D.DATASET_ID = DD.DATASET_ID WHERE DD.DOC_FILE_ID = A.DOC_FILE_ID ) AS ACTIVE_DS_CNT , ( SELECT GROUP_CONCAT(C.DS_NM SEPARATOR ', ') FROM TB_DS_DOC B INNER JOIN TB_DS C ON C.DATASET_ID = B.DATASET_ID WHERE 1 = 1 AND B.DOC_FILE_ID = A.DOC_FILE_ID ) AS DS_NM FROM TB_DOC_FILE A WHERE A.USE_YN = #{useYn, jdbcType=CHAR}
AND A.URL_ID IS NOT NULL AND A.URL_ID IS NULL
AND A.CATEGORY_ID = #{categoryId}
AND ( A.FILE_NAME LIKE CONCAT('%', #{findContent}, '%') OR A.DOC_DESC LIKE CONCAT('%', #{findContent}, '%') )
ORDER BY A.DOC_FILE_ID DESC
LIMIT #{startIndex}, #{pageSize}

mapper.insert:
/* 파일 등록 repository.insertDocFilePool */
INSERT INTO TB_DOC_FILE (
    DOC_FILE_ID
    , CATEGORY_ID
    , SEC_LVL
    , DOC_DESC
    , FILE_NAME
    , FILE_PATH
    , FILE_SIZE
    , FILE_TYPE
    , KEYWORDS
    , DOC_SRC
    , CREATE_USER_ID
    , MODIFY_USER_ID
    , USE_YN
    , CREATE_DT
    , MODIFY_DT
)
SELECT
    #{docFileId, jdbcType=VARCHAR}
    , #{categoryId, jdbcType=VARCHAR}
    , #{secLvl, jdbcType=VARCHAR}
    , #{docDesc, jdbcType=VARCHAR}
    , #{fileName, jdbcType=VARCHAR}
    , #{filePath, jdbcType=VARCHAR}
    , #{fileSize, jdbcType=BIGINT}
    , #{fileType, jdbcType=VARCHAR}
    , #{keywords, jdbcType=VARCHAR}
    , #{docSrc, jdbcType=VARCHAR}
    , #{createUserId, jdbcType=VARCHAR}
    , #{modifyUserId, jdbcType=VARCHAR}
    , #{useYn, jdbcType=CHAR}
    , NOW()
    , NOW()
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1
    FROM TB_DOC_FILE T
    WHERE T.FILE_PATH = #{filePath, jdbcType=VARCHAR}
      AND T.USE_YN = 'Y'
)

