/* 카테고리 수정 repository.renameCategory */
UPDATE TB_CONTENT_CAT
SET CATEGORY_NAME = #{categoryName, jdbcType=VARCHAR}
WHERE CATEGORY_ID = #{categoryId, jdbcType=VARCHAR}

/* 카테고리 순서·부모 단건 변경 repository.updateCategoryOrderItem */
UPDATE TB_CONTENT_CAT
SET
    PARN_CAT_ID = NULLIF(#{parnCatId, jdbcType=VARCHAR}, '')
    , SORT_ORD  = #{sortOrd, jdbcType=VARCHAR}
WHERE CATEGORY_ID = #{categoryId, jdbcType=VARCHAR}

