DELETE FROM TB_CONTENT_CAT
WHERE CATEGORY_ID = #{categoryId, jdbcType=VARCHAR}
   OR PARN_CAT_ID = #{categoryId, jdbcType=VARCHAR}

mapper.select:
/* URL 목록 건수 repository.selectUrlListCnt */
SELECT COUNT(*)
FROM TB_CNT_URL U
WHERE 1 = 1

    AND (
        U.URL_NAME LIKE CONCAT('%', #{findContent}, '%')
        OR U.URL_ADDR LIKE CONCAT('%', #{findContent}, '%')
    )


    AND U.USE_YN = #{useYn, jdbcType=CHAR}


    AND U.CATEGORY_ID = #{categoryId, jdbcType=VARCHAR}

/* URL 목록 조회 repository.selectUrlList */ SELECT U.URL_ID , U.URL_NAME , U.URL_ADDR , U.CATEGORY_ID , C.CATEGORY_NAME , U.CRAWL_INTVL , U.CRAWL_DPTH , U.USE_YN , U.LAST_CRAWL_DT , U.URL_CRAWL_STATUS_CD , U.CREATE_DT , U.MODIFY_DT , ( SELECT COUNT(*) FROM TB_DS_URL DU INNER JOIN TB_DS D ON D.DATASET_ID = DU.DATASET_ID WHERE DU.URL_ID = U.URL_ID ) AS ACTIVE_DS_CNT , ( SELECT GROUP_CONCAT(D.DS_NM SEPARATOR ', ') FROM TB_DS_URL DU INNER JOIN TB_DS D ON D.DATASET_ID = DU.DATASET_ID WHERE DU.URL_ID = U.URL_ID ) AS DS_NM FROM TB_CNT_URL U LEFT JOIN TB_CONTENT_CAT C ON C.CATEGORY_ID = U.CATEGORY_ID WHERE 1 = 1
AND ( U.URL_NAME LIKE CONCAT('%', #{findContent}, '%') OR U.URL_ADDR LIKE CONCAT('%', #{findContent}, '%') )
AND U.USE_YN = #{useYn, jdbcType=CHAR}
AND U.CATEGORY_ID = #{categoryId, jdbcType=VARCHAR}
ORDER BY U.CREATE_DT DESC
LIMIT #{startIndex}, #{pageSize}

